const { app } = require('@azure/functions');
const { CosmosClient } = require('@azure/cosmos');

const cosmosClient = new CosmosClient(process.env.COSMOS_CONNECTION_STRING);
const database = cosmosClient.database(process.env.COSMOS_DATABASE);
const container = database.container(process.env.COSMOS_CONTAINER);

const BATCH_SIZE = 100;
const MAX_EXECUTION_TIME = 570000;

app.http('batchDataProcessor', {
    methods: ['POST', 'GET'],
    authLevel: 'anonymous',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        
        context.log('Starting batch data processing');

        try {
            const requestBody = await request.text();
            let config = {};
            
            try {
                config = requestBody ? JSON.parse(requestBody) : {};
            } catch (e) {
                config = {};
            }

            const query = config.query || 'SELECT * FROM c';
            const transformFunction = config.transform || 'default';
            const outputContainer = config.outputContainer || process.env.COSMOS_OUTPUT_CONTAINER;

            const results = {
                processed: 0,
                failed: 0,
                batches: 0,
                errors: [],
                startTime: new Date(startTime).toISOString()
            };

            const querySpec = {
                query: query
            };

            const { resources: items } = await container.items
                .query(querySpec, { 
                    maxItemCount: -1,
                    enableCrossPartitionQuery: true 
                })
                .fetchAll();

            context.log(`Retrieved ${items.length} items for processing`);

            const outputContainerRef = database.container(outputContainer);

            for (let i = 0; i < items.length; i += BATCH_SIZE) {
                if (Date.now() - startTime > MAX_EXECUTION_TIME) {
                    context.log('Approaching timeout, stopping processing');
                    results.timeoutReached = true;
                    break;
                }

                const batch = items.slice(i, i + BATCH_SIZE);
                results.batches++;

                const processedBatch = await processBatch(batch, transformFunction, context);

                for (const item of processedBatch) {
                    try {
                        await outputContainerRef.items.upsert(item);
                        results.processed++;
                    } catch (error) {
                        results.failed++;
                        results.errors.push({
                            itemId: item.id,
                            error: error.message
                        });
                        context.log(`Error processing item ${item.id}: ${error.message}`);
                    }
                }

                context.log(`Processed batch ${results.batches}, total items: ${results.processed}`);
            }

            results.endTime = new Date().toISOString();
            results.duration = Date.now() - startTime;

            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(results)
            };

        } catch (error) {
            context.log(`Fatal error: ${error.message}`);
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    error: error.message,
                    stack: error.stack
                })
            };
        }
    }
});

async function processBatch(batch, transformType, context) {
    const processed = [];

    for (const item of batch) {
        try {
            let transformedItem;

            switch (transformType) {
                case 'aggregate':
                    transformedItem = aggregateTransform(item);
                    break;
                case 'enrich':
                    transformedItem = await enrichTransform(item);
                    break;
                case 'filter':
                    transformedItem = filterTransform(item);
                    break;
                case 'normalize':
                    transformedItem = normalizeTransform(item);
                    break;
                default:
                    transformedItem = defaultTransform(item);
            }

            if (transformedItem) {
                processed.push(transformedItem);
            }
        } catch (error) {
            context.log(`Error transforming item: ${error.message}`);
        }
    }

    return processed;
}

function defaultTransform(item) {
    return {
        ...item,
        processed: true,
        processedAt: new Date().toISOString(),
        version: (item.version || 0) + 1
    };
}

function aggregateTransform(item) {
    const aggregated = {
        id: item.id,
        originalData: item,
        summary: {},
        processedAt: new Date().toISOString()
    };

    for (const key in item) {
        if (typeof item[key] === 'number') {
            aggregated.summary[key] = {
                value: item[key],
                type: 'numeric'
            };
        } else if (Array.isArray(item[key])) {
            aggregated.summary[key] = {
                count: item[key].length,
                type: 'array'
            };
        }
    }

    return aggregated;
}

async function enrichTransform(item) {
    return {
        ...item,
        enriched: true,
        enrichedAt: new Date().toISOString(),
        metadata: {
            source: 'batch-processor',
            processingVersion: '1.0'
        }
    };
}

function filterTransform(item) {
    const filtered = {};
    
    for (const key in item) {
        if (key !== '_rid' && key !== '_self' && key !== '_etag' && key !== '_attachments' && key !== '_ts') {
            filtered[key] = item[key];
        }
    }

    filtered.processedAt = new Date().toISOString();
    return filtered;
}

function normalizeTransform(item) {
    const normalized = {
        id: item.id,
        data: {},
        processedAt: new Date().toISOString()
    };

    for (const key in item) {
        if (typeof item[key] === 'string') {
            normalized.data[key] = item[key].trim().toLowerCase();
        } else if (typeof item[key] === 'number') {
            normalized.data[key] = parseFloat(item[key].toFixed(2));
        } else {
            normalized.data[key] = item[key];
        }
    }

    return normalized;
}

app.timer('scheduledBatchProcessor', {
    schedule: '0 */30 * * * *',
    runOnStartup: false,
    handler: async (myTimer, context) => {
        const startTime = Date.now();
        context.log('Scheduled batch processing started');

        try {
            const querySpec = {
                query: 'SELECT * FROM c WHERE c.processed != true OR NOT IS_DEFINED(c.processed)'
            };

            const { resources: items } = await container.items
                .query(querySpec, { 
                    maxItemCount: 1000,
                    enableCrossPartitionQuery: true 
                })
                .fetchAll();

            context.log(`Found ${items.length} unprocessed items`);

            let processed = 0;
            for (const item of items) {
                if (Date.now() - startTime > MAX_EXECUTION_TIME) {
                    context.log('Timeout approaching, stopping');
                    break;
                }

                try {
                    const updated = {
                        ...item,
                        processed: true,
                        processedAt: new Date().toISOString()
                    };

                    await container.item(item.id, item.partitionKey || item.id).replace(updated);
                    processed++;
                } catch (error) {
                    context.log(`Error processing item ${item.id}: ${error.message}`);
                }
            }

            context.log(`Scheduled processing complete. Processed: ${processed}`);
        } catch (error) {
            context.log(`Scheduled processing error: ${error.message}`);
        }
    }
});

app.http('bulkImport', {
    methods: ['POST'],
    authLevel: 'anonymous',
    timeout: '00:10:00',
    handler: async (request, context) => {
        const startTime = Date.now();
        
        try {
            const body = await request.text();
            const data = JSON.parse(body);
            const items = data.items || [];

            context.log(`Starting bulk import of ${items.length} items`);

            const results = {
                imported: 0,
                failed: 0,
                errors: []
            };

            for (let i = 0; i < items.length; i += BATCH_SIZE) {
                if (Date.now() - startTime > MAX_EXECUTION_TIME) {
                    results.timeoutReached = true;
                    break;
                }

                const batch = items.slice(i, i + BATCH_SIZE);

                for (const item of batch) {
                    try {
                        await container.items.create({
                            ...item,
                            importedAt: new Date().toISOString()
                        });
                        results.imported++;
                    } catch (error) {
                        results.failed++;
                        results.errors.push({
                            item: item,
                            error: error.message
                        });
                    }
                }

                context.log(`Imported ${results.imported} of ${items.length} items`);
            }

            return {
                status: 200,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(results)
            };

        } catch (error) {
            return {
                status: 500,
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    error: error.message
                })
            };
        }
    }
});